"use server"

import { createClient, getTenantId } from "@/lib/supabase/server"

export type SearchResult = {
    id: string
    title: string
    subtitle?: string
    type: 'property' | 'lead' | 'agent'
    url: string
}

export async function globalSearch(query: string): Promise<SearchResult[]> {
    if (!query || query.length < 2) return []

    const supabase = await createClient()
    const tenantId = await getTenantId(supabase)

    if (!tenantId) return []

    const searchResults: SearchResult[] = []

    // 1. Search Properties
    const { data: properties } = await supabase
        .from("properties")
        .select("id, title, address, reference:id") // Using ID as reference for now
        .eq("tenant_id", tenantId)
        .or(`title.ilike.%${query}%,address.ilike.%${query}%`)
        .limit(5)

    if (properties) {
        properties.forEach(p => {
            searchResults.push({
                id: p.id,
                title: p.title,
                subtitle: p.address,
                type: 'property',
                url: `/propiedades/${p.id}`
            })
        })
    }

    // 2. Search Leads
    const { data: leads } = await supabase
        .from("leads")
        .select("id, name, email, phone")
        .eq("tenant_id", tenantId)
        .or(`name.ilike.%${query}%,email.ilike.%${query}%,phone.ilike.%${query}%`)
        .limit(5)

    if (leads) {
        leads.forEach(l => {
            searchResults.push({
                id: l.id,
                title: l.name,
                subtitle: l.email || l.phone,
                type: 'lead',
                url: `/clientes` // Assuming search leads takes to clients list or detail if available
            })
        })
    }

    // 3. Search Agents (Profiles)
    const { data: agents } = await supabase
        .from("profiles")
        .select("id, full_name, email")
        .eq("tenant_id", tenantId)
        .or(`full_name.ilike.%${query}%,email.ilike.%${query}%`)
        .limit(5)

    if (agents) {
        agents.forEach(a => {
            searchResults.push({
                id: a.id,
                title: a.full_name || 'Agente',
                subtitle: a.email,
                type: 'agent',
                url: `/agentes`
            })
        })
    }

    return searchResults
}
